import{_ as d,o as r,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"深化研究：数据中心参与需求响应的收益测算","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/_深化_2026-06-13_数据中心需求响应收益测算.md","filePath":"算电协同/_深化_2026-06-13_数据中心需求响应收益测算.md","lastUpdated":1781535932000}'),e={name:"算电协同/_深化_2026-06-13_数据中心需求响应收益测算.md"};function l(h,t,i,n,s,_){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="深化研究-数据中心参与需求响应的收益测算" tabindex="-1">深化研究：数据中心参与需求响应的收益测算 <a class="header-anchor" href="#深化研究-数据中心参与需求响应的收益测算" aria-label="Permalink to &quot;深化研究：数据中心参与需求响应的收益测算&quot;">​</a></h1><p><strong>日期：</strong> 2026-06-13 | <strong>来源：</strong> websearch + 研报 <strong>对应问题：</strong> 待深化问题 P0#2</p><hr><h2 id="一、核心结论" tabindex="-1">一、核心结论 <a class="header-anchor" href="#一、核心结论" aria-label="Permalink to &quot;一、核心结论&quot;">​</a></h2><p>数据中心参与需求响应的收益取决于<strong>接入方式</strong>（绿电直连 vs 现货市场 vs 辅助服务）和<strong>区域</strong>（西部资源富集区 vs 东部负荷中心）。按当前数据，典型收益区间为：</p><table tabindex="0"><thead><tr><th>方式</th><th>收益水平</th><th>典型项目</th></tr></thead><tbody><tr><td>绿电直供（电价节省）</td><td><strong>0.05-0.11元/度</strong>，年省数百万~数千万</td><td>华电新能 内蒙古和林格尔</td></tr><tr><td>需求响应/调峰辅助服务</td><td><strong>100-500元/MW/次</strong>，年化百万级</td><td>长三角试点</td></tr><tr><td>现货市场低价套利</td><td><strong>价差0.1-0.3元/度</strong>，取决于时段</td><td>甘肃/山西新能源大发时段</td></tr><tr><td>余热回收（附加）</td><td>年回收热量相当于标煤2万吨/大型DC</td><td>张家口项目</td></tr></tbody></table><hr><h2 id="二、关键数据" tabindex="-1">二、关键数据 <a class="header-anchor" href="#二、关键数据" aria-label="Permalink to &quot;二、关键数据&quot;">​</a></h2><h3 id="_2-1-国家级示范项目-华电新能-×-和林格尔" tabindex="-1">2.1 国家级示范项目：华电新能 × 和林格尔 <a class="header-anchor" href="#_2-1-国家级示范项目-华电新能-×-和林格尔" aria-label="Permalink to &quot;2.1 国家级示范项目：华电新能 × 和林格尔&quot;">​</a></h3><p><strong>项目概况：</strong> 我国首个&quot;风光储直供算力&quot;国家级算电协同标杆工程</p><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>一期风光规模</td><td>36万千瓦</td></tr><tr><td>年供绿电</td><td>7.6亿度</td></tr><tr><td>到户电价</td><td><strong>0.36元/度</strong>（较市场均价低5-6分）</td></tr><tr><td>企业端节省</td><td>并行科技年省<strong>630万元</strong>（当前算力规模）</td></tr><tr><td>项目端年收益</td><td><strong>约2.7亿元</strong>（较传统外送溢价15%-20%）</td></tr><tr><td>二期/三期总规模</td><td>86万千瓦，2026年底建成</td></tr><tr><td>绿电直供占比</td><td>&gt;80%</td></tr><tr><td>综合PUE</td><td>1.15（行业平均1.5）</td></tr></tbody></table><p><strong>来源：</strong> 华电新能（600930）公告 + 北极星电力网</p><h3 id="_2-2-内蒙古乌兰察布智算中心-优刻得" tabindex="-1">2.2 内蒙古乌兰察布智算中心（优刻得） <a class="header-anchor" href="#_2-2-内蒙古乌兰察布智算中心-优刻得" aria-label="Permalink to &quot;2.2 内蒙古乌兰察布智算中心（优刻得）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>绿电占比</td><td>80%</td></tr><tr><td>绿电电价</td><td><strong>0.25元/度</strong></td></tr><tr><td>单机柜年电费</td><td>26,280元（12kW机柜）</td></tr><tr><td>单机柜年收入</td><td>12万元（月租金1万元）</td></tr><tr><td>2300机柜年毛利</td><td><strong>1.73亿元</strong></td></tr><tr><td>毛利率</td><td>62.7%（vs 公司整体18.86%）</td></tr></tbody></table><p><strong>来源：</strong> 东方财富网·优刻得分析</p><h3 id="_2-3-全国数据中心灵活性潜力-学术研究" tabindex="-1">2.3 全国数据中心灵活性潜力（学术研究） <a class="header-anchor" href="#_2-3-全国数据中心灵活性潜力-学术研究" aria-label="Permalink to &quot;2.3 全国数据中心灵活性潜力（学术研究）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>来源</th></tr></thead><tbody><tr><td>2030年数据中心电力负荷</td><td><strong>1.05亿千瓦</strong></td><td>北京理工大学</td></tr><tr><td>2030年数据中心用电量</td><td><strong>5,257.6亿千瓦时</strong></td><td>北京理工大学</td></tr><tr><td>2030年灵活性资源</td><td><strong>2.3万~4.0万MW</strong></td><td>BIT期刊</td></tr><tr><td>碳减排潜力</td><td>43.4%</td><td>测算</td></tr><tr><td>运行成本降幅</td><td>35.3%</td><td>测算</td></tr><tr><td>2025年数据中心用电量</td><td>1,933亿度（占全社会1.9%）</td><td>国家能源局</td></tr><tr><td>2026年1-2月用电增速</td><td><strong>同比+46.2%</strong></td><td>中电联</td></tr></tbody></table><h3 id="_2-4-各区域数据中心绿电电价优势" tabindex="-1">2.4 各区域数据中心绿电电价优势 <a class="header-anchor" href="#_2-4-各区域数据中心绿电电价优势" aria-label="Permalink to &quot;2.4 各区域数据中心绿电电价优势&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算力枢纽</th><th>最优绿电来源</th><th>电价优势</th><th>对比工商业电价</th></tr></thead><tbody><tr><td>内蒙古/甘肃/宁夏</td><td>风电直供</td><td>0.2583元/度起</td><td>显著低于</td></tr><tr><td>京津冀/长三角</td><td>垃圾焚烧发电</td><td>0.02-0.11元/度优势</td><td>小幅节省</td></tr><tr><td>贵州/川渝</td><td>水电</td><td>0.25-0.30元/度</td><td>明显优势</td></tr></tbody></table><blockquote><p><strong>关键判断：</strong> 风电直供数据中心所需最低电价0.2583元/度（8%资本金IRR），已低于多数西部省份现货电价，直供模式在资源富集区经济性确定。</p></blockquote><hr><h2 id="三、需求响应收益粗算模型" tabindex="-1">三、需求响应收益粗算模型 <a class="header-anchor" href="#三、需求响应收益粗算模型" aria-label="Permalink to &quot;三、需求响应收益粗算模型&quot;">​</a></h2><h3 id="模型1-调峰辅助服务" tabindex="-1">模型1：调峰辅助服务 <a class="header-anchor" href="#模型1-调峰辅助服务" aria-label="Permalink to &quot;模型1：调峰辅助服务&quot;">​</a></h3><ul><li>数据中心可压减非关键算力负荷 20-30%</li><li>单个10MW数据中心：可提供 <strong>2-3MW</strong> 调峰容量</li><li>辅助服务补偿：100-500元/MW/次（各省差异大）</li><li>年化收益：<strong>20-50万元/年</strong>（假设每周参与2次）</li></ul><h3 id="模型2-现货市场价差套利" tabindex="-1">模型2：现货市场价差套利 <a class="header-anchor" href="#模型2-现货市场价差套利" aria-label="Permalink to &quot;模型2：现货市场价差套利&quot;">​</a></h3><ul><li>新能源大发时段（午间）电价低至地板价（甘肃/山东常见）</li><li>晚高峰电价可超千元/MWh</li><li>可转移负荷比例：批处理任务 30-50%</li><li>单个10MW数据中心年化收益：<strong>30-80万元</strong></li></ul><h3 id="模型3-绿电直供综合收益" tabindex="-1">模型3：绿电直供综合收益 <a class="header-anchor" href="#模型3-绿电直供综合收益" aria-label="Permalink to &quot;模型3：绿电直供综合收益&quot;">​</a></h3><ul><li>电价节省 0.05-0.10元/度</li><li>10MW数据中心年用电约8,760万度</li><li><strong>年省电费：400-900万元</strong>（核心收益来源）</li></ul><hr><h2 id="四、待验证问题" tabindex="-1">四、待验证问题 <a class="header-anchor" href="#四、待验证问题" aria-label="Permalink to &quot;四、待验证问题&quot;">​</a></h2><ol><li>各省调峰辅助服务补偿标准差异大，需逐省确认</li><li>数据中心实际可压减负荷比例取决于业务类型（推理负载vs训练负载）</li><li>绿电直供的输电通道占用费各省不同</li><li>容量电价政策对数据中心参与需求响应的影响</li></ol><hr><h2 id="五、数据来源" tabindex="-1">五、数据来源 <a class="header-anchor" href="#五、数据来源" aria-label="Permalink to &quot;五、数据来源&quot;">​</a></h2><ul><li>华电新能（600930）公告</li><li>财联社 2026-06-03 数据中心基建调研</li><li>北京理工大学学报（社科版）2025</li><li>中国银河证券 数据中心低碳电力研报</li><li>北极星电力网 2026-04-09 内蒙古&quot;人工智能+&quot;方案</li><li>东方财富·优刻得乌兰察布项目分析</li><li>RMI 2025 电力市场化改革报告</li></ul>',34)])])}const u=d(e,[["render",l]]);export{g as __pageData,u as default};
